import { useState, useEffect, useCallback, useRef } from "react";

const LOGO_IMG = "data:image/jpeg;base64,";

const INITIAL_ENERGY = 500;
const MAX_ENERGY = 500;
const ENERGY_REGEN_RATE = 1;
const COINS_PER_TAP = 1;
const MINING_RATE = 0.05;

const LEVELS = [
  { name: "مبتدی", min: 0, max: 1000, color: "#888" },
  { name: "برنزی", min: 1000, max: 5000, color: "#cd7f32" },
  { name: "نقره‌ای", min: 5000, max: 20000, color: "#C0C0C0" },
  { name: "طلایی", min: 20000, max: 100000, color: "#FFD700" },
  { name: "الماسی", min: 100000, max: Infinity, color: "#b9f2ff" },
];

const MOCK_FRIENDS = [
  { name: "رسول نذافی", coins: 48200, avatar: "👤" },
  { name: "پدرام علی پور", coins: 32100, avatar: "👤" },
  { name: "زهره", coins: 21000, avatar: "👤" },
];

const MOCK_LEADERBOARD = [
  { name: "CryptoKing", coins: 245000 },
  { name: "TapMaster", coins: 198000 },
  { name: "GoldMiner", coins: 156000 },
  { name: "شما", coins: 0, isMe: true },
  { name: "CoinHunter", coins: 89000 },
];

function formatNumber(n) {
  if (n >= 1e6) return (n / 1e6).toFixed(1) + "M";
  if (n >= 1e3) return (n / 1e3).toFixed(1) + "K";
  return Math.floor(n).toLocaleString("fa-IR");
}

function getLevel(coins) {
  return LEVELS.find((l) => coins >= l.min && coins < l.max) || LEVELS[0];
}

export default function AvinCoinApp() {
  const [coins, setCoins] = useState(1240);
  const [energy, setEnergy] = useState(INITIAL_ENERGY);
  const [tab, setTab] = useState("tap");
  const [tapEffects, setTapEffects] = useState([]);
  const [isTapping, setIsTapping] = useState(false);
  const [referralCopied, setReferralCopied] = useState(false);
  const [miningAccumulated, setMiningAccumulated] = useState(0);
  const coinRef = useRef(null);
  const tapIdRef = useRef(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setEnergy((e) => Math.min(MAX_ENERGY, e + ENERGY_REGEN_RATE));
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setMiningAccumulated((m) => m + MINING_RATE);
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  const handleTap = useCallback(
    (e) => {
      if (energy < COINS_PER_TAP) return;
      const rect = coinRef.current?.getBoundingClientRect();
      const clientX = e.touches ? e.touches[0].clientX : e.clientX;
      const clientY = e.touches ? e.touches[0].clientY : e.clientY;
      const x = rect ? clientX - rect.left : 100;
      const y = rect ? clientY - rect.top : 100;

      setCoins((c) => c + COINS_PER_TAP);
      setEnergy((en) => Math.max(0, en - COINS_PER_TAP));
      setIsTapping(true);
      setTimeout(() => setIsTapping(false), 100);

      tapIdRef.current += 1;
      const id = tapIdRef.current;
      setTapEffects((prev) => [...prev, { id, x, y }]);
      setTimeout(() => {
        setTapEffects((prev) => prev.filter((ef) => ef.id !== id));
      }, 800);
    },
    [energy]
  );

  const claimMining = () => {
    if (miningAccumulated < 1) return;
    setCoins((c) => c + Math.floor(miningAccumulated));
    setMiningAccumulated(0);
  };

  const level = getLevel(coins);
  const nextLevel = LEVELS[LEVELS.indexOf(level) + 1];
  const progress = nextLevel
    ? ((coins - level.min) / (nextLevel.min - level.min)) * 100
    : 100;

  const leaderboard = [...MOCK_LEADERBOARD]
    .map((e) => (e.isMe ? { ...e, coins } : e))
    .sort((a, b) => b.coins - a.coins);

  return (
    <div style={styles.root}>
      <div style={styles.bg} />

      {/* Header */}
      <div style={styles.header}>
        <div style={styles.headerLeft}>
          <div style={styles.avatar}>🦖</div>
          <div>
            <div style={styles.username}>کاربر تلگرام</div>
            <div style={{ ...styles.levelBadge, color: level.color }}>
              ⭐ {level.name}
            </div>
          </div>
        </div>
        <div style={styles.coinDisplay}>
          <img src={LOGO_IMG} alt="coin" style={{ width: 20, height: 20, borderRadius: "50%", objectFit: "cover" }} />
          <span style={styles.coinCount}>{formatNumber(coins)}</span>
        </div>
      </div>

      {/* Level Progress */}
      <div style={styles.progressWrap}>
        <div style={styles.progressBar}>
          <div
            style={{
              ...styles.progressFill,
              width: `${progress}%`,
              background: `linear-gradient(90deg, ${level.color}, #fff8)`,
            }}
          />
        </div>
        <div style={styles.progressLabel}>
          {nextLevel
            ? `تا ${nextLevel.name}: ${formatNumber(nextLevel.min - coins)}`
            : "حداکثر سطح!"}
        </div>
      </div>

      {/* Tab Content */}
      {tab === "tap" && (
        <div style={styles.tapSection}>
          {miningAccumulated >= 1 && (
            <div style={styles.miningBanner} onClick={claimMining}>
              <span>⛏️ {formatNumber(miningAccumulated)} اوو تماته آماده دریافت</span>
              <span style={styles.claimBtn}>دریافت</span>
            </div>
          )}

          <div style={styles.coinArea}>
            {tapEffects.map((ef) => (
              <div
                key={ef.id}
                style={{
                  ...styles.tapEffect,
                  left: ef.x - 15,
                  top: ef.y - 20,
                }}
              >
                +{COINS_PER_TAP}
              </div>
            ))}
            <div
              ref={coinRef}
              style={{
                ...styles.coinButton,
                transform: isTapping ? "scale(0.93)" : "scale(1)",
                boxShadow: isTapping
                  ? "0 0 30px #FFD70066"
                  : "0 0 80px #FFD70055, 0 8px 32px #0008",
              }}
              onClick={handleTap}
              onTouchStart={handleTap}
            >
              <img
                src={LOGO_IMG}
                alt="tap coin"
                style={{
                  width: "100%",
                  height: "100%",
                  borderRadius: "50%",
                  objectFit: "cover",
                  display: "block",
                  pointerEvents: "none",
                }}
              />
            </div>
            <div style={styles.tapHint}>
              {energy === 0 ? "⚡ در حال شارژ..." : "ضربه بزن!"}
            </div>
          </div>

          <div style={styles.energySection}>
            <div style={styles.energyLabel}>
              <span>⚡ انرژی</span>
              <span>{Math.floor(energy)} / {MAX_ENERGY}</span>
            </div>
            <div style={styles.energyBar}>
              <div
                style={{
                  ...styles.energyFill,
                  width: `${(energy / MAX_ENERGY) * 100}%`,
                  background:
                    energy < 100
                      ? "linear-gradient(90deg,#ff4444,#ff8800)"
                      : "linear-gradient(90deg,#00e5ff,#7c4fff)",
                }}
              />
            </div>
          </div>

          <div style={styles.statsRow}>
            <div style={styles.statBox}>
              <div style={styles.statVal}>+{COINS_PER_TAP}</div>
              <div style={styles.statLbl}>هر ضربه</div>
            </div>
            <div style={styles.statBox}>
              <div style={styles.statVal}>{MINING_RATE * 3600}/h</div>
              <div style={styles.statLbl}>مایننگ</div>
            </div>
            <div style={styles.statBox}>
              <div style={styles.statVal}>{formatNumber(coins)}</div>
              <div style={styles.statLbl}>کل سکه</div>
            </div>
          </div>
        </div>
      )}

      {tab === "friends" && (
        <div style={styles.section}>
          <div style={styles.sectionTitle}>👥 دوستان خود را دعوت کن</div>
          <div style={styles.referralCard}>
            <div style={styles.referralDesc}>
              به ازای هر دوست دعوت شده <strong>+500 سکه</strong> دریافت کن!
            </div>
            <div style={styles.referralCode}>t.me/AvinCoinBot?start=REF12345</div>
            <button
              style={styles.copyBtn2}
              onClick={() => {
                setReferralCopied(true);
                setTimeout(() => setReferralCopied(false), 2000);
              }}
            >
              {referralCopied ? "✅ کپی شد!" : "📋 کپی لینک"}
            </button>
          </div>

          <div style={styles.sectionTitle}>دوستان من</div>
          {MOCK_FRIENDS.map((f, i) => (
            <div key={i} style={styles.friendRow}>
              <div style={styles.friendAvatar}>{f.avatar}</div>
              <div style={{ flex: 1 }}>
                <div style={styles.friendName}>{f.name}</div>
                <div style={styles.friendCoins}>🪙 {formatNumber(f.coins)} سکه</div>
              </div>
              <div style={styles.friendBonus}>+250</div>
            </div>
          ))}
        </div>
      )}

      {tab === "leaderboard" && (
        <div style={styles.section}>
          <div style={styles.sectionTitle}>🏆 جدول برترین‌ها</div>
          {leaderboard.map((p, i) => (
            <div
              key={i}
              style={{
                ...styles.lbRow,
                background: p.isMe
                  ? "linear-gradient(90deg,#7c4fff22,#00e5ff22)"
                  : i === 0 ? "#FFD70015" : "transparent",
                border: p.isMe ? "1px solid #7c4fff55" : "1px solid #ffffff0a",
              }}
            >
              <div
                style={{
                  ...styles.lbRank,
                  color: i === 0 ? "#FFD700" : i === 1 ? "#C0C0C0" : i === 2 ? "#cd7f32" : "#ffffff44",
                }}
              >
                {i === 0 ? "🥇" : i === 1 ? "🥈" : i === 2 ? "🥉" : `#${i + 1}`}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ ...styles.lbName, color: p.isMe ? "#00e5ff" : "#fff" }}>
                  {p.name} {p.isMe && "(شما)"}
                </div>
              </div>
              <div style={styles.lbCoins}>🪙 {formatNumber(p.coins)}</div>
            </div>
          ))}
        </div>
      )}

      {tab === "mine" && (
        <div style={styles.section}>
          <div style={styles.sectionTitle}>⛏️ مایننگ خودکار</div>
          <div style={styles.mineCard}>
            <div style={styles.mineStatus}>
              <img src={LOGO_IMG} alt="mine" style={{ width: 50, height: 50, borderRadius: "50%", objectFit: "cover" }} />
              <div>
                <div style={styles.mineTitle}>مایننگ فعال است</div>
                <div style={styles.mineRate}>{MINING_RATE * 3600} سکه در ساعت</div>
              </div>
            </div>
            <div style={styles.mineAccum}>
              <div style={styles.mineAccumLabel}>جمع‌آوری شده</div>
              <div style={styles.mineAccumVal}>🪙 {miningAccumulated.toFixed(2)}</div>
              <button
                style={{ ...styles.claimMineBtn, opacity: miningAccumulated >= 1 ? 1 : 0.4 }}
                onClick={claimMining}
                disabled={miningAccumulated < 1}
              >
                دریافت سکه‌ها
              </button>
            </div>
          </div>

          <div style={styles.sectionTitle}>ارتقاء مایننگ</div>
          {[
            { name: "کارگر اضافه", bonus: "+0.02/s", cost: 5000 },
            { name: "ابزار بهتر", bonus: "+0.05/s", cost: 15000 },
            { name: "معدن بزرگتر", bonus: "+0.1/s", cost: 50000 },
          ].map((upg, i) => (
            <div key={i} style={styles.upgradeRow}>
              <div style={{ flex: 1 }}>
                <div style={styles.upgradeName}>{upg.name}</div>
                <div style={styles.upgradeBonus}>{upg.bonus}</div>
              </div>
              <button
                style={{ ...styles.upgradeBtn, opacity: coins >= upg.cost ? 1 : 0.4 }}
                onClick={() => { if (coins >= upg.cost) setCoins((c) => c - upg.cost); }}
              >
                🪙 {formatNumber(upg.cost)}
              </button>
            </div>
          ))}
        </div>
      )}

      {/* Bottom Nav */}
      <div style={styles.bottomNav}>
        {[
          { id: "tap", label: "ضربه", icon: "👆" },
          { id: "mine", label: "مایننگ", icon: "⛏️" },
          { id: "friends", label: "دوستان", icon: "👥" },
          { id: "leaderboard", label: "رتبه‌بندی", icon: "🏆" },
        ].map((t) => (
          <button
            key={t.id}
            style={{
              ...styles.navBtn,
              color: tab === t.id ? "#FFD700" : "#ffffff55",
              borderTop: tab === t.id ? "2px solid #FFD700" : "2px solid transparent",
            }}
            onClick={() => setTab(t.id)}
          >
            <span style={styles.navIcon}>{t.icon}</span>
            <span style={styles.navLabel}>{t.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}

