  progressBar: { height: 4, background: "#ffffff15", borderRadius: 4, overflow: "hidden" },
  progressFill: { height: "100%", borderRadius: 4, transition: "width 0.5s" },
  progressLabel: { fontSize: 10, color: "#ffffff55", marginTop: 4, textAlign: "left" },
